#include <iostream>
#include <sstream>
#include <vector>

class Solution {
public:
    int countElements(std::string s) {
        std::istringstream iss(s);
        int count = 0;
        for (std::string token; std::getline(iss, token, ' ');)
            count++;
        return count;
    }
};

int main() {
    std::string s;
    std::getline(std::cin, s);
    Solution solution;
    std::cout << solution.countElements(s) << std::endl;
    return 0;
}
